#include <stdio.h>
int main()
{
    int n, x, x2;
    x2 = 0;
    scanf("%d", &n);
    getchar();
    char tree[102];
    gets(tree);
    char plant[3];
    for (int i = 0; i < n; i++) {
        x = 0;
        for (int j = 0; j < n; j++) {
            if (tree[j] == tree[i] && tree[j+1] == tree[i+1]) {
                x++;
            }
        }
        if (x > x2) {
            x2 = x;
            plant[0] = tree[i];
            plant[1] = tree[i+1];
        }
    }
    printf("%c%c\n", plant[0], plant[1]);
    return 0;
}

